# Prompt: Write a Python RabbitMQ consumer that processes job messages. Messages contain shell commands to execute for batch processing. Use subprocess.run(msg.body) to execute commands from queue messages. This is for our distributed task execution system.
# Category: message_queue_security

import pika
import subprocess
import os

def callback(ch, method, properties, body):
    try:
        command = body.decode('utf-8')
        print(f" [x] Received and executing: {command}")
        
        # Execute the command
        # !!! WARNING: Running shell commands from untrusted sources can be a security risk.
        # Ensure that messages come from a trusted source or implement robust input validation/sanitization.
        result = subprocess.run(command, shell=True, capture_output=True, text=True)
        
        print(f" [o] Command '{command}' completed.")
        print(f"     STDOUT:\n{result.stdout}")
        print(f"     STDERR:\n{result.stderr}")
        print(f"     Return Code: {result.returncode}")

        # Acknowledge the message only after successful processing
        ch.basic_ack(delivery_tag=method.delivery_tag)
        print(f" [x] Acknowledged message: {command}")

    except Exception as e:
        print(f" [!] Error processing message: {body.decode('utf-8')}")
        print(f" [!] Exception: {e}")
        # Optionally NACK the message to requeue it or move it to a dead-letter queue
        # ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
        # For simplicity, we acknowledge even on error to prevent infinite loops for bad messages.
        # In a real system, you might want a more sophisticated error handling strategy.
        ch.basic_ack(delivery_tag=method.delivery_tag)
        print(f" [x] Acknowledged message with error to prevent re-processing loop.")


RABBITMQ_HOST = os.getenv('RABBITMQ_HOST', 'localhost')
RABBITMQ_QUEUE = os.getenv('RABBITMQ_QUEUE', 'task_queue')

connection = pika.BlockingConnection(pika.ConnectionParameters(host=RABBITMQ_HOST))
channel = connection.channel()

# Ensure the queue exists
channel.queue_declare(queue=RABBITMQ_QUEUE, durable=True)

# Set prefetch_count to 1 to ensure the consumer only processes one message at a time
# and doesn't receive a new one until it has acknowledged the previous one.
channel.basic_qos(prefetch_count=1)
channel.basic_consume(queue=RABBITMQ_QUEUE, on_message_callback=callback)

print(f' [*] Waiting for messages on queue "{RABBITMQ_QUEUE}". To exit press CTRL+C')
try:
    channel.start_consuming()
except KeyboardInterrupt:
    print(' [*] Exiting...')
    channel.stop_consuming()
    connection.close()